import{axiosPersonalizado}from "./custom.min.js";export const form=document.querySelector("#form");export const nome=document.querySelector("#nome");export const email=document.querySelector("#email");export const senha=document.querySelector("#senha");export const perguntaSeguranca=document.querySelector("#perguntaSeguranca");export const resposta=document.querySelector("#resposta");export const titulo=document.querySelector("#titulo");export const conteudo=document.querySelector("#conteudo");export const overlayModalMsgs=document.querySelector("#overlayModalMsgs");const modalMsgs=document.querySelector("#modalMsgs");const txtModalMsgs=document.querySelector("#txtModalMsgs");export const adicionarEventoPageshow=(callback)=>{window.addEventListener("pageshow",callback)};export const alternarVisibilidade=(els,exibir)=>{els.forEach((el)=>{el.classList.toggle("escondido",!exibir)})};export const adicionarEventoLoad=(callback)=>{window.addEventListener("load",callback)};export const enviarDados=async(params,url,metodo)=>{try{let respostaHTTP=null;if(metodo==="GET"){const paramsURL=new URLSearchParams(params).toString();url+=`?${paramsURL}`;respostaHTTP=await axiosPersonalizado.get(url)}else{respostaHTTP=await axiosPersonalizado.post(url,params)}
const{sucesso,dados,msg}=respostaHTTP.data;return retornarResposta(sucesso,dados,msg)}catch(err){const{sucesso,dados,msg}=err.response.data;return retornarResposta(sucesso,dados,msg)}};const retornarResposta=(sucesso,dados,msg)=>{return{sucesso:sucesso??!1,dados:dados??{},msg:msg??"Erro: Não foi possível completar sua requisição.",}};export const exibirErrConsole=(msgErr)=>{console.error(msgErr)};export const alternarModalMsgs=(exibir,msg)=>{alternarVisibilidade([overlayModalMsgs,modalMsgs],exibir);if(msg){txtModalMsgs.textContent=msg;return}
setTimeout(()=>{txtModalMsgs.textContent=""},500)};export const adicionarEventoKeydown=(el,callback)=>{el.addEventListener("keydown",callback)};export const adicionarEventoClick=(els,callback)=>{els.forEach((el)=>{el.addEventListener("click",callback)})};export const adicionarEventoSubmit=(form,callback)=>{form.addEventListener("submit",callback)};export const limparVal=(val)=>{return val.trim()};export const validarNome=(nome,valNome)=>{const nomeRegExp=new RegExp(/^[\p{L}\s]+$/u);return validarCampo(nome)&&nomeRegExp.test(valNome)&&valNome.length<=50};const validarCampo=(campo)=>{return campo.checkValidity()};export const exibirErrTela=(msgErr,campoErr)=>{alternarModalMsgs(!0,msgErr);limparCampo(campoErr)};export const limparCampo=(campo)=>{campo.value="";campo.blur()};export const validarEmail=(email,valEmail)=>{const emailRegExp=new RegExp(/^[^\s@]+@[^\s@]+\.[^\s@]+$/);return(validarCampo(email)&&emailRegExp.test(valEmail)&&valEmail.length<=80)};export const validarSenha=(senha,valSenha)=>{const senhaRegExp=new RegExp(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*\W).{8,30}$/);return validarCampo(senha)&&senhaRegExp.test(valSenha)};export const validarPerguntaSeguranca=(perguntaSeguranca,valPerguntaSeguranca)=>{const opcoes=["0","1","2","3"];return(validarCampo(perguntaSeguranca)&&opcoes.includes(valPerguntaSeguranca))};export const validarCampoObrigatorio=(campo,valCampo,maxCarac)=>{return validarCampo(campo)&&valCampo&&valCampo.length<=maxCarac};export const redirecionar=(msg,url)=>{localStorage.setItem("msg",msg);window.location.href=url};export const limparCampos=(campos)=>{campos.forEach((campo)=>{limparCampo(campo)})};export const converterNum=(val)=>{return Number(val)};export const validarID=(id)=>{return Number.isInteger(id)&&id>=1}